import { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Store from './pages/Store';
import MyApps from './pages/MyApps';
import History from './pages/History';
import { getInstalledApps } from './api';
import './App.css';

export default function App() {
  const [page, setPage]           = useState('store');
  const [installedCount, setInstalledCount] = useState(0);
  const [refreshKey, setRefreshKey] = useState(0);

  const sync = () => {
    getInstalledApps().then(apps => setInstalledCount(apps.length));
    setRefreshKey(k => k + 1);
  };

  useEffect(() => { sync(); }, []);

  return (
    <div className="app">
      <Navbar page={page} setPage={setPage} installedCount={installedCount} />
      <main className="main-content">
        {page === 'store'   && <Store onInstallChange={sync} />}
        {page === 'myapps'  && <MyApps refreshTrigger={refreshKey} onInstallChange={sync} />}
        {page === 'history' && <History />}
      </main>
    </div>
  );
}
